`timescale 1ns/1psmodule tb_uart();    localparam int CLK_PERIOD     = 20;    localparam int BIT_CLKS       = 5200;    localparam int BYTE_CLKS      = 52000;    localparam int TIMEOUT_BYTE   = 65000;    localparam int TIMEOUT_RESULT = 200;    localparam int N              = 4;    localparam int IN_WIDTH       = 8;    localparam int ACC_WIDTH      = 32;    localparam int BYTES_RESULT   = ACC_WIDTH / 8;    // Clock    logic clk = 0;    logic rst_n;    always #(CLK_PERIOD/2) clk = ~clk;    // uart_top DUT    logic       u_rx_drive;    logic       u_rx;    logic       u_tx;    logic [7:0] u_tx_din;    logic       u_tx_wr;    logic       u_tx_full;    logic [7:0] u_rx_dout;    logic       u_rx_rd;    logic       u_rx_empty;    logic       loopback_en;    always_comb begin        if (loopback_en) u_rx = u_tx;        else             u_rx = u_rx_drive;    end    uart_top u_uart_dut (        .clk(clk), .rst_n(rst_n),        .rx(u_rx), .tx(u_tx),        .tx_din(u_tx_din), .tx_wr(u_tx_wr), .tx_full(u_tx_full),        .rx_dout(u_rx_dout), .rx_rd(u_rx_rd), .rx_empty(u_rx_empty)    );    // system_top DUT    logic s_rx;    logic s_tx;    logic s_is_signed;    system_top #(.N(N), .IN_WIDTH(IN_WIDTH), .ACC_WIDTH(ACC_WIDTH)) u_sys (        .clk(clk), .rst_n(rst_n),        .rx(s_rx), .is_signed(s_is_signed), .tx(s_tx)    );    // Scoreboard    int pass_cnt;    int fail_cnt;    task automatic chk_pass(input string msg);        pass_cnt++;        $display("  [PASS] %s", msg);    endtask    task automatic chk_fail(input string msg);        fail_cnt++;        $display("  [FAIL] %s", msg);    endtask    // Send one byte via bit-bang    task automatic uart_send_byte(ref logic line, input logic [7:0] data);        int i;        line = 1'b0;        repeat(BIT_CLKS) @(posedge clk);        for (i = 0; i < 8; i++) begin            line = data[i];            repeat(BIT_CLKS) @(posedge clk);        end        line = 1'b1;        repeat(BIT_CLKS) @(posedge clk);    endtask    // Core recv: wait for start bit (timeout_cyc), sample 8 bits    task automatic recv_core(        input  int   sel,        input  int   timeout_cyc,        output logic [7:0] data,        output logic ok    );        int   cnt;        int   i;        logic cur;        ok  = 1'b0;        cnt = 0;        data = 8'h00;        forever begin            @(posedge clk);            cur = (sel == 0) ? u_tx : s_tx;            if (cur === 1'b0) break;            cnt++;            if (cnt > timeout_cyc) begin                $display("  [TIMEOUT] recv_core sel=%0d", sel);                data = 8'hXX;                return;            end        end        repeat(BIT_CLKS / 2) @(posedge clk);        for (i = 0; i < 8; i++) begin            repeat(BIT_CLKS) @(posedge clk);            data[i] = (sel == 0) ? u_tx : s_tx;        end        repeat(BIT_CLKS) @(posedge clk);        ok = 1'b1;    endtask    task automatic recv_u_tx(output logic [7:0] data);        logic ok;        recv_core(0, TIMEOUT_BYTE, data, ok);    endtask    task automatic recv_s_tx(output logic [7:0] data);        logic ok;        recv_core(1, TIMEOUT_BYTE, data, ok);    endtask    task automatic recv_s_tx_first(output logic [7:0] data, output logic ok);        recv_core(1, BYTE_CLKS * TIMEOUT_RESULT, data, ok);    endtask    // TC1: uart_tx sends 0xA5, verify bit pattern    task automatic tc1_uart_tx();        logic [7:0] test_byte;        logic [7:0] got;        int         bit_errs;        int         wait_cnt;        int         i;        $display("\n--- TC1: uart_tx single byte (0xA5) ---");        test_byte = 8'hA5;        bit_errs  = 0;        got       = 8'h00;        @(negedge clk); u_tx_din = test_byte; u_tx_wr = 1'b1;        @(negedge clk); u_tx_wr  = 1'b0;        wait_cnt = 0;        while (u_tx !== 1'b0) begin            @(posedge clk);            wait_cnt++;            if (wait_cnt > TIMEOUT_BYTE) begin                chk_fail("TC1: timeout waiting for start bit");                return;            end        end        chk_pass("TC1: start bit detected");        repeat(BIT_CLKS / 2) @(posedge clk);        if (u_tx !== 1'b0) chk_fail("TC1: start bit not 0 at mid-sample");        else                chk_pass("TC1: start bit = 0 at mid-sample");        for (i = 0; i < 8; i++) begin            repeat(BIT_CLKS) @(posedge clk);            got[i] = u_tx;            if (u_tx !== test_byte[i]) bit_errs++;        end        if (bit_errs == 0)            chk_pass($sformatf("TC1: all 8 data bits correct (0x%02X)", got));        else            chk_fail($sformatf("TC1: %0d bit error(s) got=0x%02X exp=0x%02X",                                bit_errs, got, test_byte));        repeat(BIT_CLKS) @(posedge clk);        if (u_tx !== 1'b1) chk_fail("TC1: stop bit not 1");        else                chk_pass("TC1: stop bit = 1");    endtask    // TC2: inject 0x3C into uart_rx, read from RX FIFO    task automatic tc2_uart_rx();        logic [7:0] test_byte;        int         wait_cnt;        $display("\n--- TC2: uart_rx single byte (0x3C) ---");        test_byte = 8'h3C;        fork uart_send_byte(u_rx_drive, test_byte); join_none        wait_cnt = 0;        while (u_rx_empty) begin            @(posedge clk);            wait_cnt++;            if (wait_cnt > TIMEOUT_BYTE * 2) begin                chk_fail("TC2: timeout");                return;            end        end        chk_pass("TC2: byte arrived in RX FIFO");        @(negedge clk); u_rx_rd = 1'b1;        @(negedge clk); u_rx_rd = 1'b0;        repeat(3) @(posedge clk);        if (u_rx_dout === test_byte)            chk_pass($sformatf("TC2: RX FIFO = 0x%02X OK", u_rx_dout));        else            chk_fail($sformatf("TC2: RX FIFO = 0x%02X expected 0x%02X",                                u_rx_dout, test_byte));    endtask    // TC3: loopback 4 bytes through TX->RX    task automatic tc3_loopback();        logic [7:0] send_data [4];        int         wait_cnt;        int         i;        $display("\n--- TC3: UART loopback tx->rx, 4 bytes ---");        send_data[0] = 8'hDE;        send_data[1] = 8'hAD;        send_data[2] = 8'hBE;        send_data[3] = 8'hEF;        for (i = 0; i < 4; i++) begin            @(negedge clk); u_tx_din = send_data[i]; u_tx_wr = 1'b1;            @(negedge clk); u_tx_wr  = 1'b0;            wait_cnt = 0;            while (u_rx_empty) begin                @(posedge clk);                wait_cnt++;                if (wait_cnt > TIMEOUT_BYTE * 3) begin                    chk_fail($sformatf("TC3[%0d]: timeout", i));                    return;                end            end            @(negedge clk); u_rx_rd = 1'b1;            @(negedge clk); u_rx_rd = 1'b0;            repeat(3) @(posedge clk);            if (u_rx_dout === send_data[i])                chk_pass($sformatf("TC3[%0d]: 0x%02X looped back OK", i, u_rx_dout));            else                chk_fail($sformatf("TC3[%0d]: got=0x%02X exp=0x%02X",                                    i, u_rx_dout, send_data[i]));        end    endtask    // TC5: Identity(4x4) x Identity(4x4) = Identity(4x4)    task automatic tc5_identity();        logic [7:0]  mat_a [0:N-1][0:N-1];        logic [7:0]  mat_b [0:N-1][0:N-1];        logic [7:0]  rb    [0:N-1][0:N-1][0:BYTES_RESULT-1];        logic [31:0] res;        logic [31:0] exp_val;        logic        ok;        int          errs;        int          r, c, b;        $display("\n--- TC5: system_top N=4 -- Identity x Identity = Identity ---");        s_is_signed = 1'b0;        errs = 0;        for (r = 0; r < N; r++)            for (c = 0; c < N; c++) begin                mat_a[r][c] = (r == c) ? 8'd1 : 8'd0;                mat_b[r][c] = (r == c) ? 8'd1 : 8'd0;            end        $display("  Sending A...");        for (r = 0; r < N; r++)            for (c = 0; c < N; c++)                uart_send_byte(s_rx, mat_a[r][c]);        $display("  Sending B...");        for (r = 0; r < N; r++)            for (c = 0; c < N; c++)                uart_send_byte(s_rx, mat_b[r][c]);        chk_pass("TC5: 32 bytes sent");        $display("  Waiting for result...");        recv_s_tx_first(rb[0][0][0], ok);        if (!ok) begin            chk_fail("TC5: timeout waiting for result");            return;        end        chk_pass("TC5: result TX started");        for (b = 1; b < BYTES_RESULT; b++)            recv_s_tx(rb[0][0][b]);        for (r = 0; r < N; r++)            for (c = 0; c < N; c++) begin                if (r == 0 && c == 0) continue;                for (b = 0; b < BYTES_RESULT; b++)                    recv_s_tx(rb[r][c][b]);            end        chk_pass($sformatf("TC5: %0d bytes received", N*N*BYTES_RESULT));        for (r = 0; r < N; r++)            for (c = 0; c < N; c++) begin                res     = {rb[r][c][3], rb[r][c][2], rb[r][c][1], rb[r][c][0]};                exp_val = (r == c) ? 32'd1 : 32'd0;                if (res !== exp_val) begin                    errs++;                    $display("  [MISMATCH] C[%0d][%0d] = %0d expected %0d",                             r, c, res, exp_val);                end            end        if (errs == 0) chk_pass($sformatf("TC5: ALL %0d elements correct", N*N));        else           chk_fail($sformatf("TC5: %0d element(s) WRONG", errs));    endtask    // TC6: All-1 x All-2 = All-8    task automatic tc6_all_ones();        logic [7:0]  mat_a [0:N-1][0:N-1];        logic [7:0]  mat_b [0:N-1][0:N-1];        logic [7:0]  rb    [0:N-1][0:N-1][0:BYTES_RESULT-1];        logic [31:0] res;        logic [31:0] exp_val;        logic        ok;        int          errs;        int          r, c, b;        $display("\n--- TC6: system_top N=4 -- All-1 x All-2 = All-%0d ---", N*2);        s_is_signed = 1'b0;        errs = 0;        for (r = 0; r < N; r++)            for (c = 0; c < N; c++) begin                mat_a[r][c] = 8'd1;                mat_b[r][c] = 8'd2;            end        $display("  Sending matrices...");        for (r = 0; r < N; r++)            for (c = 0; c < N; c++)                uart_send_byte(s_rx, mat_a[r][c]);        for (r = 0; r < N; r++)            for (c = 0; c < N; c++)                uart_send_byte(s_rx, mat_b[r][c]);        chk_pass("TC6: 32 bytes sent");        $display("  Waiting for result...");        recv_s_tx_first(rb[0][0][0], ok);        if (!ok) begin            chk_fail("TC6: timeout waiting for result");            return;        end        chk_pass("TC6: result TX started");        for (b = 1; b < BYTES_RESULT; b++)            recv_s_tx(rb[0][0][b]);        for (r = 0; r < N; r++)            for (c = 0; c < N; c++) begin                if (r == 0 && c == 0) continue;                for (b = 0; b < BYTES_RESULT; b++)                    recv_s_tx(rb[r][c][b]);            end        chk_pass($sformatf("TC6: %0d bytes received", N*N*BYTES_RESULT));        exp_val = 32'(N * 2);        for (r = 0; r < N; r++)            for (c = 0; c < N; c++) begin                res = {rb[r][c][3], rb[r][c][2], rb[r][c][1], rb[r][c][0]};                if (res !== exp_val) begin                    errs++;                    $display("  [MISMATCH] C[%0d][%0d] = %0d expected %0d",                             r, c, res, exp_val);                end            end        if (errs == 0) chk_pass($sformatf("TC6: ALL %0d elements = %0d", N*N, N*2));        else           chk_fail($sformatf("TC6: %0d element(s) WRONG", errs));    endtask    // Main    initial begin        pass_cnt    = 0;        fail_cnt    = 0;        u_rx_drive  = 1'b1;        s_rx        = 1'b1;        s_is_signed = 1'b0;        u_tx_din    = 8'h00;        u_tx_wr     = 1'b0;        u_rx_rd     = 1'b0;        loopback_en = 1'b0;        rst_n = 1'b0; repeat(10) @(posedge clk);        rst_n = 1'b1; repeat(5)  @(posedge clk);        $display("====================================================");        $display("  UART TESTBENCH  CLK=50MHz  BAUD~9600  OS=16x");        $display("  BIT_CLKS=%0d  BYTE_CLKS=%0d  N=%0d",                 BIT_CLKS, BYTE_CLKS, N);        $display("====================================================");        tc1_uart_tx();        tc2_uart_rx();        loopback_en = 1'b1;        tc3_loopback();        loopback_en = 1'b0;        rst_n = 1'b0; repeat(10) @(posedge clk);        rst_n = 1'b1; repeat(5)  @(posedge clk);        tc5_identity();        rst_n = 1'b0; repeat(10) @(posedge clk);        rst_n = 1'b1; repeat(5)  @(posedge clk);        tc6_all_ones();        repeat(10) @(posedge clk);        $display("\n====================================================");        $display("  RESULT:  PASS=%0d  FAIL=%0d", pass_cnt, fail_cnt);        if (fail_cnt == 0)            $display("  >> ALL TESTS PASSED <<");        else            $display("  >> %0d FAILURE(S) <<", fail_cnt);        $display("====================================================\n");        #100 $finish;    endendmodule